629		private static segmentCost(
630			values: number[],
631			start: number,
632			end: number,
633			method: string,
634		): number {
635			const segment = values.slice(start, end + 1);
636			const n = segment.length;
637			if (n === 0) return Infinity;
638			if (n === 1) return 0;
639	
640			const variance = this.variance({ values: segment, precision: null });
641	
642			switch (method) {
643				case 'mean':
644					return variance === 0 ? 0 : n * Math.log(Math.max(variance, 1e-10));
645				case 'variance':
646				case 'meanvar':
647					return variance === 0
648						? 0
649						: n * Math.log(Math.max(2 * Math.PI * variance, 1e-10)) + n;
650				default:
651					throw new Error(`Unknown method: ${method}`);
652			}
653		}
